'use strict';

var callBound = require('call-bound');

var $PromiseThen = callBound('Promise.prototype.then', true);

var isObject = require('es-object-atoms/isObject');



module.exports = function IsPromise(x) {
	if (!isObject(x)) {
		return false;
	}
	if (!$PromiseThen) { 
		return false;
	}
	try {
		$PromiseThen(x); 
	} catch (e) {
		return false;
	}
	return true;
};
